#include <bits/stdc++.h>
using namespace std;

const int N=440,M=(160*280+160+280)*2,INF=0x3f3f3f3f;

int m,n;
int head[N],ver[M],edge[M],nxt[M],tot=1;
int s,t,d[N],now[N];

void add(int x,int y,int z){
    ver[++tot]=y,edge[tot]=z,nxt[tot]=head[x],head[x]=tot;
    ver[++tot]=x,edge[tot]=0,nxt[tot]=head[y],head[y]=tot;
}

bool bfs(){
    memset(d,0,sizeof(d));
    queue<int> q;
    q.push(s);
    d[s]=1,now[s]=head[s];
    while(q.size()){
        int x=q.front();
        q.pop();
        for(int i=head[x],y;i;i=nxt[i])
            if(!d[y=ver[i]] && edge[i]){
                d[y]=d[x]+1,now[y]=head[y];
                if(y==t)
                    return 1;
                q.push(y);
            }
    }
    return 0;
}

int Dinic(int x,int flow){
    if(x==t)
        return flow;
    int res=0;
    for(int i=now[x],y;i && res<flow;i=nxt[i]){
        now[x]=i,y=ver[i];
        if(d[y]==d[x]+1 && edge[i]){
            int tmp=Dinic(y,min(edge[i],flow-res));
            if(!tmp)
                d[y]=0;
            edge[i]-=tmp,edge[i^1]+=tmp;
            res+=tmp;
        }
    }
    return res;
}

int main(){
    scanf("%d%d",&m,&n);
    s=m+n+1,t=m+n+2;
    int sum=0;
    for(int i=1,r;i<=m;i++){
        scanf("%d",&r);
        sum+=r;
        add(s,i,r);
    }
    for(int i=1,c;i<=n;i++){
        scanf("%d",&c);
        add(i+m,t,c);
    }
    for(int i=1;i<=m;i++)
        for(int j=1;j<=n;j++)
            add(i,j+m,1);
    int flow,max_flow=0;
    while(bfs())
        while(flow=Dinic(s,INF))
            max_flow+=flow;
    if(max_flow==sum){
        puts("1");
        vector<int> ans[160];
        for(int i=2*(n+m)+2;i<=tot;i+=2)
            if(edge[i^1])
                ans[ver[i^1]].push_back(ver[i]-m);
        for(int i=1;i<=m;i++){
            for(int x:ans[i])
                printf("%d ",x);
            puts("");
        }
    }else
        puts("0");
    return 0;
}
